// Construir mensajes para citas de mañana (ya filtradas por PostgreSQL)
const diasSemana = ['domingo','lunes','martes','miércoles','jueves','viernes','sábado'];
const meses = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];

const manana = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Bogota' }));
manana.setDate(manana.getDate() + 1);
const fechaNatural = `${diasSemana[manana.getDay()]} ${manana.getDate()} de ${meses[manana.getMonth()]}`;

const resultados = [];

for (const item of $input.all()) {
  const row = item.json;
  const numero = (row['Número'] || '').toString().trim().replace(/@s\.whatsapp\.net/g, '').replace(/\D/g, '');
  const nombre = (row['Nombre'] || 'cliente').toString().trim();
  const businessName = (row['business_name'] || 'nuestro negocio').toString().trim();
  const hora = (row['Hora'] || '').toString().trim().substring(0,5);
  const servicio = (row['Servicio'] || '').toString().trim();

  if (numero && hora) {
    const mensaje = `Hola ${nombre} 👋\n\nTe recordamos que tienes una cita en *${businessName}* mañana *${fechaNatural}* a las *${hora.substring(0,5)}*.\n\n✂️ Servicio: *${servicio}*\n\nSi necesitas cancelar o reagendar, responde este mensaje 😊`;
    resultados.push({ json: { numero, nombre, mensaje, hora, servicio } });
  }
}

return resultados;
